#include <bits/stdc++.h>
using namespace std;

bool fact(int n){
    if(n<2)return false;
    for(int i=2;i*i<=n;i++)
        if(n%i==0)return false;
    return true;
}

bool check(int n){
    while(n){
        if(!fact(n))return false;
        n/=10;
    }
    return true;
}

int main(){
    int n,m;
    cin>>n>>m;
    for(int i=n;i<=m;i++){
        if(check(i))cout<<i<<endl;
    }
    return 0;
}
